import{_ as t,c as a,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Advanced Features","description":"Deep dive into the core technology of Markdown table formatting, including OpenCode concealment mode principles, table specifications, and alignment details. Master the plugin's working principles comprehensively.","frontmatter":{"title":"Advanced Features","subtitle":"Advanced Features: Deep Dive into Markdown Table Formatting Technical Details","sidebarTitle":"Advanced Features","order":2,"description":"Deep dive into the core technology of Markdown table formatting, including OpenCode concealment mode principles, table specifications, and alignment details. Master the plugin's working principles comprehensively.","prerequisite":["start-getting-started","start-features"],"tags":["Advanced","Principles","Specifications"]},"headers":[],"relativePath":"franlol/opencode-md-table-formatter/advanced/index.md","filePath":"franlol/opencode-md-table-formatter/advanced/index.md"}`),o={name:"franlol/opencode-md-table-formatter/advanced/index.md"};function r(l,e,s,c,d,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="advanced-features-deep-dive-into-markdown-table-formatting-technical-details" tabindex="-1">Advanced Features: Deep Dive into Markdown Table Formatting Technical Details <a class="header-anchor" href="#advanced-features-deep-dive-into-markdown-table-formatting-technical-details" aria-label="Permalink to &quot;Advanced Features: Deep Dive into Markdown Table Formatting Technical Details&quot;">​</a></h1><h2 id="chapter-overview" tabindex="-1">Chapter Overview <a class="header-anchor" href="#chapter-overview" aria-label="Permalink to &quot;Chapter Overview&quot;">​</a></h2><p>This chapter explores the technical details of Markdown table formatting in depth, including how OpenCode concealment mode works, the structural specifications for valid tables, and detailed explanations of alignment methods. By learning this content, you will fully understand how the plugin processes table formatting and how to avoid common errors.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><p>It is recommended to study the content of this chapter in the following order:</p><div class="info custom-block"><p class="custom-block-title">Learning Path</p><ol><li><strong>Concealment Mode Principles</strong> → Understand why OpenCode&#39;s concealment mode requires special handling</li><li><strong>Table Specifications</strong> → Master which types of tables can be correctly formatted</li><li><strong>Alignment Details</strong> → Learn how to control table alignment and aesthetics</li></ol></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting this chapter, make sure you have:</p><ul><li>[x] Completed <a href="./../start/getting-started/">Get Started in One Minute</a>, successfully installed and configured the plugin</li><li>[x] Read <a href="./../start/features/">Feature Overview</a>, understood the basic features of the plugin</li></ul><div class="warning custom-block"><p class="custom-block-title">Important Note</p><p>If you haven&#39;t completed the basic learning yet, it&#39;s recommended to start with the <a href="./../start/getting-started/">Getting Started Guide</a>.</p></div><h2 id="course-navigation" tabindex="-1">Course Navigation <a class="header-anchor" href="#course-navigation" aria-label="Permalink to &quot;Course Navigation&quot;">​</a></h2><h3 id="concealment-mode-principles" tabindex="-1"><a href="./concealment-mode/">Concealment Mode Principles</a> <a class="header-anchor" href="#concealment-mode-principles" aria-label="Permalink to &quot;[Concealment Mode Principles](./concealment-mode/)&quot;">​</a></h3><p>Understand how OpenCode&#39;s concealment mode works and how the plugin correctly calculates display width. You will learn:</p><ul><li>What concealment mode is and why it requires special handling</li><li>How the Markdown symbol stripping algorithm works</li><li>The role of <code>Bun.stringWidth()</code> in width calculation</li></ul><p><strong>Estimated time</strong>: 8 minutes | <strong>Difficulty</strong>: Intermediate | <strong>Prerequisite</strong>: Feature Overview</p><hr><h3 id="table-specifications" tabindex="-1"><a href="./table-spec/">Table Specifications</a> <a class="header-anchor" href="#table-specifications" aria-label="Permalink to &quot;[Table Specifications](./table-spec/)&quot;">​</a></h3><p>Master the structural requirements for valid Markdown tables to avoid &quot;invalid table&quot; errors. You will learn:</p><ul><li>What table structures are valid</li><li>The purpose and format requirements of separator rows</li><li>The principle of column count consistency checking</li><li>How to quickly identify table structure issues</li></ul><p><strong>Estimated time</strong>: 6 minutes | <strong>Difficulty</strong>: Beginner | <strong>Prerequisite</strong>: Concealment Mode Principles</p><hr><h3 id="alignment-details" tabindex="-1"><a href="./alignment/">Alignment Details</a> <a class="header-anchor" href="#alignment-details" aria-label="Permalink to &quot;[Alignment Details](./alignment/)&quot;">​</a></h3><p>Master the syntax and effects of the three alignment methods to make tables more beautiful. You will learn:</p><ul><li>Syntax for left-aligned, center-aligned, and right-aligned</li><li>How to specify alignment in the separator row</li><li>Cell content padding algorithm</li><li>The relationship between alignment and display width</li></ul><p><strong>Estimated time</strong>: 10 minutes | <strong>Difficulty</strong>: Intermediate | <strong>Prerequisite</strong>: Table Specifications</p><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h2><p>After completing this chapter, you will:</p><ul><li>✅ Understand the working principles of OpenCode concealment mode</li><li>✅ Master the structural requirements for valid tables</li><li>✅ Be able to identify and fix invalid tables</li><li>✅ Proficiently use the three alignment methods</li><li>✅ Understand the internal technical implementation details of the plugin</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can:</p><ol><li><strong>Solve Practical Problems</strong> → Learn <a href="./../../faq/troubleshooting/">Common Issues</a> to quickly locate and resolve problems</li><li><strong>Understand Technical Boundaries</strong> → Read <a href="./../../appendix/limitations/">Known Limitations</a> to understand the applicable scenarios of the plugin</li><li><strong>Deep Dive into Implementation</strong> → Check <a href="./../../appendix/tech-details/">Technical Details</a> to learn about caching mechanisms and performance optimization</li></ol><hr><div class="tip custom-block"><p class="custom-block-title">Practical Advice</p><p>If you want to quickly solve table formatting issues, you can start by reading the <a href="./table-spec/">Table Specifications</a> section of this chapter, which contains the most common invalid table cases.</p></div>',34)])])}const u=t(o,[["render",r]]);export{m as __pageData,u as default};
